import json
from typing import Any, Dict

def save_preferences(preferences: Dict[str, Any], filename: str) -> None:
    with open(filename, 'w') as f:
        json.dump(preferences, f)

def load_preferences(filename: str) -> Dict[str, Any]:
    try:
        with open(filename, 'r') as f:
            preferences = json.load(f)
            return validate_preferences(preferences)
    except FileNotFoundError:
        return {}
    except json.JSONDecodeError:
        raise ValueError("Invalid JSON in file")

def validate_preferences(preferences: Dict[str, Any]) -> Dict[str, Any]:
    for key, value in preferences.items():
        if isinstance(value, dict):
            preferences[key] = validate_preferences(value)
        elif not isinstance(value, (int, float, str, list)):
            raise ValueError("Invalid preference type")
    return preferences